const URL = require('url');
const psl = require('psl');
const cheerio = require('cheerio');

const result_normalize_options = {
	removeDirectoryIndex: true,
	removeTrailingSlash: true,
	stripWWW: true,
	stripFragment: true,
	normalizeHttps: false,
	normalizeProtocol: true,
	<PLACEHOLDER>
